                    int closestIdx = 0;
                    int closestDist = (presets[0] - currentVal).abs();
                    for (int i = 1; i < presets.length; i++) {
                      final dist = (presets[i] - currentVal).abs();
                      if (dist < closestDist) {
                        closestDist = dist;
                        closestIdx = i;
